var e=JSON.parse(`[{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"모네! 모네네네!!","JPN":"モネ！　モネネネ！！","ENG":"Mone! Monenene!","TWN":"莫妮！莫妮妮妮！！"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"이제 어떡해요, 실장님? 수가 줄기는커녕 점점 늘어나고 있잖아요!","JPN":"どうしますか、室長？　数が減るどころか、どんどん増えてるじゃないですか！","ENG":"What do we do now, Chief? They're multiplying!","TWN":"現在怎麼辦，室長？數量不僅沒有減少，反而還越來越多！"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"이상해. 펭귄 친구들은 다들 착하단 말이야.","JPN":"おかしいね。ペンギンちゃんたちはみんないい子なのに。","ENG":"That's strange. The penguins are all nice.","TWN":"奇怪。企鵝朋友們都很善良的。"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"이렇게까지 화낼 리가 없는데?","JPN":"ここまで怒るはずないんだけど？","ENG":"I don't know why they're so angry.","TWN":"不至於這麼生氣吧？"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네! 모네네네!","JPN":"モネ！　モネネネ！","ENG":"Mone! Monenene!","TWN":"莫妮！莫妮妮妮！"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"싫습니다. 이건 크레데레가 정당한 값을 지불하고 얻은 거예요.","JPN":"イヤです。これはクレデレが正当な対価を支払って得たものです。","ENG":"No. Credere acquired these by legitimate means.","TWN":"不行，這是克蕾妲莉花錢買來的。"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"돌려받고 싶다면 세 배를 지불하세요, 현실은 녹록치 않은 법입니다.","JPN":"返してほしいのなら、3倍出しなさい。現実はそう甘くないのです。","ENG":"Pay triple the price if you want these back. Reality is harsh, so you will have to deal with it.","TWN":"如果想要拿回去，就付三倍的價錢吧，現實是很殘酷的。"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"아직도 실랑이 중이잖아! 그 정도면 좀 양보하라고요!","JPN":"まだ揉めてる！　そのくらいで譲ってやりなさいよ！","ENG":"She's still trying to rip them off! Oh, come on! Just give up already!","TWN":"還在爭嗎！都這樣了你就讓個步吧！"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"싫어요. 남은 용돈을 탈탈 털어 준비한 회심의 사업이란 말입니다.","JPN":"イヤです。少ないお小遣いをかき集めて準備した会心の事業なんですよ。","ENG":"No. Credere used up all her remaining allowance to start this business.","TWN":"不行。這可是克蕾妲莉把剩下的零用錢全部掏出來，打算做一個穩賺不賠的生意的。"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"혹여 이분들의 법적 소유주가 있어 재물손괴죄가 성립되는 건 아닌지 조사했어요.","JPN":"もしも、この方々に法的持ち主がいて器物損壊罪が成立するのではないかと調査しました。","ENG":"Credere had to investigate whether or not they had a legal owner to make her guilty of theft.","TWN":"克蕾妲莉怕犯下財物損毀罪，還特地調查過原本是否有合法所有人……"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"합법입니다. 꼬우면 돈 가져오세요.","JPN":"合法です。気に入らなかったらお金を持ってきなさい。","ENG":"And Credere is not doing anything illegal. So, bring Credere money if you want these.","TWN":"結果，克蕾妲莉是合法的，不服的話就拿錢來吧。"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"어라.","JPN":"あれ。","ENG":"Huh?","TWN":"哎呀。"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"엣취.","JPN":"くしゅん。","ENG":"Ah-choo!","TWN":"哈啾。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"자요. 코 좀 푸세요.","JPN":"はい。鼻かんでください。","ENG":"Here. Blow your nose.","TWN":"給你，把鼻涕擤一擤吧。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"크레데레는 콧물 같은 거 안 흘립니다, 훌쩍.","JPN":"クレデレは鼻水なんて流しません、スンッ。","ENG":"Credere never has a runny nose. *Sniffle*","TWN":"克蕾妲莉不會流鼻涕的，吸吸。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네? 모네네?","JPN":"モネ？　モネネ？","ENG":"Mone? Monene?","TWN":"莫妮？莫妮妮？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네네! 모네네네!","JPN":"モネネ！　モネネネ！","ENG":"Monene! Monenene!","TWN":"莫妮妮！莫妮妮妮！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"다행이다. 유피가 과자를 줘서 펭귄들도 화가 풀렸나 봐.","JPN":"よかった。ユピがお菓子をあげて、ペンギンも怒りが収まったみたい。","ENG":"That's a relief. Seems like the penguins are happy with the snacks you gave them.","TWN":"太好了。幸虧有悠菲的點心，企鵝們好像消氣了。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"나름 자신작이거든요. 누구 고집 탓에 전부 꼬일 뻔했지만.","JPN":"これ自信作なんです。誰かさんの我がままのせいで、全部ダメになるところでしたけど。","ENG":"I'm pretty confident with them. A certain somebody's stubbornness almost ruined the whole thing, though.","TWN":"這是我的得意之作。雖然差點因為某人的固執全賠進去了。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"옷도 잘 입고 다니시는 분이 뭐가 아쉬워서 펭귄들 상대로 횡포를 부리던 거예요?","JPN":"立派な服を着てる方が、どうしてペンギン相手に横暴な振る舞いをしてたんですか？","ENG":"You don't seem like you need money. Why were you trying to take advantage of the penguins?","TWN":"你看起來也不像缺錢的人，為什麼要對企鵝們做這種事？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"아빠가, 훌쩍. 독립하고 싶으면 뭐라도 해보라고, 훌쩍.","JPN":"お父さんが、スンッ。独立したいならなんでもやってみろって、スンッ。","ENG":"Dad. *Sniffle* He told me to do something if Credere wanted to move out. *Sniffle*","TWN":"爸爸說，吸吸。如果想要獨立，就去做點什麼，吸吸。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"그렇게 된 겁니다.","JPN":"それでこうなったわけです。","ENG":"So, that's what happened.","TWN":"……事情就是這樣。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"네. 하나도 모르겠어요. 이상한 짓 말고 얌전히 집에나 가세요.","JPN":"まったく、なんのことだが。変なことしてないで、大人しく家に帰ってください。","ENG":"Right. I didn't understand any of that. Don't do anything reckless and just go home.","TWN":"是是是。我完全不明白。小孩子就別做奇怪的事，乖乖回家去吧。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"무리입니다. 방금 펭귄분들에게 전재산을 빼앗겨 버렸거든요.","JPN":"無理です。さっきペンギンに全財産を奪われてしまいました。","ENG":"Credere can't. The penguins just took all her money.","TWN":"不行。克蕾妲莉剛剛被企鵝們搶走了全部財產。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"어린아이를 상대로 횡포라니.","JPN":"子ども相手に横暴なんて。","ENG":"Credere can't believe they would take advantage of a child.","TWN":"居然占小孩子便宜。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"크레데레는 오늘 법치주의 국가의 한계를 느꼈습니다.","JPN":"クレデレは今日、法治国家の限界を感じました。","ENG":"Credere is realizing the limits of this constitutional nation.","TWN":"克蕾妲莉今天感受到了法治國家的有限。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"횡포는 당신이 지금 저지르는 짓이 부모님에 대한 횡포겠죠.","JPN":"横暴は、今あなたがやってることが両親に対する横暴でしょう。","ENG":"Don't you think that you might be the one taking advantage of your parents?","TWN":"你現在所做的事情就不是占父母的便宜？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"나이도 어리면서 사업은 무슨 사업이에요?","JPN":"幼いのに事業ってどういうことですか？","ENG":"You're so young, why are you obsessed with this business of yours?","TWN":"年紀輕輕的，為什麼會想要出來做生意？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"놉. 원래 호랑이굴에 들어가도 정신만 차리면 그만입니다.","JPN":"ちっちっ。虎穴に入らずんば虎子を得ず、なんです。","ENG":"Nope. Even if one is on the edge of a cliff, one just needs to get it together to survive.","TWN":"不，既然入了虎穴，只要保持清醒就行了。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"해적분들에게 공감을 얻으려면 호랑이보다 상어가 낫겠습니다만.","JPN":"海賊の方々から共感してもらうには、虎よりサメの方が良さそうですね。","ENG":"Since you're pirates, \\"the end of the plank\\" might be more appropriate than a cliff.","TWN":"用海盜們的話來講，把老虎換成鯊魚更容易理解。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"오오. 선장님의 해적스러움을 눈치채다니 제법이군!","JPN":"おお。船長の海賊らしさに気付くなんて、なかなかやるね！","ENG":"Ooh. You've noticed how pirate-y I am. Impressive!","TWN":"喔喔，你竟然能察覺到西格瑪船長的海盜氣質，好眼力！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"아뇨. 그냥 얼핏 들어서 알았습니다.","JPN":"いいえ。なんとなくわかったんです。","ENG":"Not really. Credere just overheard you talking.","TWN":"沒有，克蕾妲莉是湊巧聽到的。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"힝.","JPN":"ひぃん。","ENG":"Oh.","TWN":"嘖。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"그럼 이쯤에서 크레데레의 은혜 갚기 타임-.","JPN":"それでは、この辺でクレデレの恩返しタイムー","ENG":"And now, Credere's special favor-repaying time.","TWN":"那麼現在是克蕾妲莉的報恩時間。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L20_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"두 분께는 특별히 크레데레를 데려갈 기회를 드리겠습니다.","JPN":"お二人には特別に、クレデレを連れて行くチャンスを与えて差し上げます。","ENG":"You two lucky pirates have the exclusive opportunity to take Credere with you.","TWN":"兩位將有特別機會帶走克蕾妲莉。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L21_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"고용 조건은 놀랍게도 삼시 세끼가 끝.","JPN":"雇用の条件はなんと、一日三食だけ。","ENG":"Providing Credere with meals every day is the only condition for employing her.","TWN":"雇傭條件竟然只需要包三餐。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L22_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"와, 크레데레. 싸다 싸.","JPN":"わーい、クレデレ。お得お得。","ENG":"Wow, Credere. So cost-efficient. So cheap.","TWN":"哇，克蕾妲莉。真是划算，便宜！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L24_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"돈 없고 배고프니까 그냥 빌붙겠단 소리잖아요.","JPN":"お金ないしお腹も空いてるから寄生するってことじゃないですか。","ENG":"You just want to leech on us because you're broke and hungry.","TWN":"沒錢沒吃的，所以你是說要賴上我們了吧。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"들을 가치도 없네요. 가요, 실장님.","JPN":"聞く価値もないですね。行きましょう、室長。","ENG":"It's not even worth listening to. Let's leave, Chief.","TWN":"這傢伙滿嘴胡說八道。走吧，室長。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"음. 해적단에 온 걸 환영한다, 크레데레 선원!","JPN":"うむ。海賊団へようこそ、クレデレ船員！","ENG":"Mm. Welcome to the crew, Credere!","TWN":"嗯，歡迎加入海盜團，克蕾妲莉船員！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"이건 선장님이 주는 입단 선물이야!","JPN":"これは船長からの入団プレゼントね！","ENG":"This is a welcome gift from your captain!","TWN":"這是船長給你的入團禮物！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"RIBBON_DEBT_NULL_NULL","text":{"KOREA":"아싸.","JPN":"やった。","ENG":"Yay.","TWN":"耶嘿——"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L32_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"네. 이렇게 될 줄 얼핏 알았어요.","JPN":"はい。なんとなくこうなるってわかっていました。","ENG":"Right. I thought that this might happen.","TWN":"嗯，我就知道會是這樣……"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"모르겠다. 스트레스 받으니 과자나…","JPN":"もう知らない。ストレス溜まるから、お菓子でも……","ENG":"I give up. I'm stressed. I'm just going to eat the snack–","TWN":"我放棄了。壓力好大，吃點零食吧……"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":" 응?","JPN":" うん？","ENG":" Hmm?","TWN":"嗯？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"당신. 그거 어디서 났어요?","JPN":"あなた。それ、どこから？","ENG":"Wait. Where did you get that?","TWN":"欸，你手上那東西是從哪裡來的？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"무얼 숨기랴. 아까 싸우실 때 슬쩍 했습니다.","JPN":"何を隠そう。さっきの小競り合いでこっそりと。","ENG":"No skeletons in this closet. Credere pickpocketed this while you were fighting.","TWN":"克蕾妲莉沒有秘密。剛才戰鬥的時候順手拿的。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"허기진 크레데레는 치타만큼이나 민첩하니까요.","JPN":"飢えてるクレデレは、チーターくらい素早いですから。","ENG":"A hungry Credere is as dexterous as a cheetah.","TWN":"餓了的克蕾妲莉和獵豹一樣敏捷。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"못 해 먹겠어요, 실장님. 전 이만 돌아갈래요.","JPN":"もうやってらんない、室長。私はもう帰ります。","ENG":"I can't do this anymore, Chief. I'm heading back.","TWN":"我做不下去了，室長！我回去了！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L46_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"어딜!","JPN":"させない！","ENG":"Not a chance!","TWN":"想得美！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L49_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"과연. 집단의 상하관계를 완벽하게 파악했습니다.","JPN":"なるほど。集団の上下関係を完璧に把握しました。","ENG":"Interesting. Credere now understands the hierarchy of this group.","TWN":"有趣。克蕾妲莉已經完美掌握了這裡的上下關係。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"시그마 해적단. 문자 그대로 시그마가 갑인 집단이로군요.","JPN":"シグマ海賊団。文字どおりシグマが甲である集団なんですね。","ENG":"The Sigma Pirates. So quite literally, Sigma is the boss.","TWN":"西格瑪海盜團。字面意思，就是以西格瑪為首的海盜團。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그것보다 제 손에 이건 뭐죠…?","JPN":"それより、私の手にあるこれはなんですか……？","ENG":"More importantly, what's this in my hand...?","TWN":"對了，我手上的這是什麼……？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"과자 값인 크레데레의 칭찬도장입니다.","JPN":"お菓子代のクレデレのよくできましたステッカーです。","ENG":"Credere's \\"good job\\" stamps. In exchange for the snacks.","TWN":"這是作為拿走點心的交換，克蕾妲莉的好寶寶印章。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"30장을 모으면, 세상에. 귀여운 크레데레가 언제 어디서든 한 번 안아드린답니다.","JPN":"30枚集めると、なんと。可愛いクレデレがいつどこでも一度だけ抱きしめて差し上げます。","ENG":"Get 30 stamps and wow. The adorable Credere will hug you at any place at any time.","TWN":"集齊30個，喔喔，可愛的克蕾妲莉會隨時隨地給你一個擁抱。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L7_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"하아.","JPN":"はあ。","ENG":"*Sigh*","TWN":"哀——"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"미래가 암담하구나…….","JPN":"お先真っ暗……","ENG":"I have a bad outlook on all of this...","TWN":"我的未來一片黯淡……"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};